 1	import * as React from 'react';
 2	import NamespaceSafetyBox from '@odf/core/components/utils/safety-box';
 3	import { ModalFooter } from '@odf/shared/generic';
 4	import { ModalBody, ModalTitle } from '@odf/shared/generic/ModalTitle';
 5	import { SecretModel } from '@odf/shared/models';
 6	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 7	import { k8sDelete } from '@openshift-console/dynamic-plugin-sdk';
 8	import { ModalComponent } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 9	import {
10	  Modal,
11	  Button,
12	  ModalVariant,
13	  FlexItem,
14	  Flex,
15	} from '@patternfly/react-core';
16	import { useODFNamespaceSelector } from '../../redux';
17	
18	type RotateKeysModalProps = ModalComponent<{
19	  isOpen: boolean;
20	}>;
21	
22	export const RotateKeysModal: RotateKeysModalProps = ({
23	  isOpen,
24	  closeModal,
25	}) => {
26	  const { t } = useCustomTranslation();
27	  const { odfNamespace } = useODFNamespaceSelector();
28	  const MODAL_TITLE = t('Rotate signing keys');
29	  const [inProgress, setProgress] = React.useState(false);
30	  const [error, setError] = React.useState<Error>(null);
31	
32	  const onRotate = () => {
33	    setProgress(true);
34	    k8sDelete({
35	      model: SecretModel,
36	      resource: {
37	        metadata: {
38	          name: 'onboarding-ticket-key',
39	          namespace: odfNamespace,
40	        },
41	      },
42	    })
43	      .then(() => {
44	        setProgress(false);
45	        closeModal();
46	      })
47	      .catch((err) => {
48	        setProgress(false);
49	        setError(err);
50	      });
51	  };
52	
53	  return (
54	    <Modal isOpen={isOpen} onClose={closeModal} variant={ModalVariant.medium}>
55	      <ModalTitle>{MODAL_TITLE}</ModalTitle>
56	      <NamespaceSafetyBox>
57	        <ModalBody>
58	          <Flex direction={{ default: 'column' }}>
59	            <FlexItem grow={{ default: 'grow' }}>
60	              <div>
61	                {t(
62	                  'This action will rotate the signing key currently used for generating and validating client onboarding tokens.'
63	                )}
64	              </div>
65	              <div>
66	                {t(
67	                  'Upon rotation, the existing signing key will be revoked and replaced with a new one.'
68	                )}
69	              </div>
70	            </FlexItem>
71	          </Flex>
72	        </ModalBody>
73	        <ModalFooter inProgress={inProgress} errorMessage={error?.message}>
74	          <Flex direction={{ default: 'row' }}>
75	            <FlexItem>
76	              <Button variant="secondary" onClick={() => closeModal()}>
77	                {t('Cancel')}
78	              </Button>
79	            </FlexItem>
80	            <FlexItem>
81	              <Button onClick={() => onRotate()}>{t('Confirm')}</Button>
82	            </FlexItem>
83	          </Flex>
84	        </ModalFooter>
85	      </NamespaceSafetyBox>
86	    </Modal>
87	  );
88	};

